html:
{%- set no_default_print_heading = 1 -%}
{%- from "templates/print_formats/standard_macros.html" import add_header -%}

<div class="main-container">
  {{ add_header(0, 1, doc, letter_head, no_letterhead, print_settings) }}

  <style>
  {%- set border_inset = 0 -%}
  {%- set content_inner_padding = 3 -%}

  html, body { margin:0; padding:0; height:100%; font-family: Arial, sans-serif; font-size: 13px; }

  .letter-head img,
  .letter-head .logo,
  .letter-head .logo img,
  .header-logo img,
  .company-logo img {
    max-width: 160px !important;
    max-height: 90px !important;
    width: auto !important;
    height: auto !important;
    object-fit: contain !important;
    display: inline-block !important;
  }

  .print-format {
    position:relative;
    background:transparent !important;
    margin:0 !important;
    padding:0;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .page-border {
    position:fixed;
    top:{{ border_inset }}mm;
    left:{{ border_inset }}mm;
    right:{{ border_inset }}mm;
    bottom:{{ border_inset }}mm;
    border:1px solid #000;
    z-index:0;
    pointer-events:none;
  }

  .main-container {
    position:relative;
    z-index:1;
    padding:{{ content_inner_padding }}mm;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .print-heading,
  .print-heading + div { display:none !important; }

  .heading-label {
    font-size:18px;
    font-weight:600;
    text-align:center;
    color:#222;
    margin-bottom:2px;
    letter-spacing:1px;
    text-transform:uppercase;
    font-family: Arial, sans-serif;
  }

  .cash-account-label {
    font-size:15px;
    font-weight:700;
    text-align:center;
    color:#000;
    margin-bottom:6px;
    font-family: Arial, sans-serif;
    letter-spacing:0.5px;
  }

  .section { margin-bottom:1px; }

  .section-title {
    font-size:13px;
    font-weight:600;
    border-bottom:1px solid #000;
    color:#000;
    margin-bottom:2px;
    padding-bottom:1px;
    font-family: Arial, sans-serif;
  }

  .letter-head {
    margin-bottom:2mm !important;
  }

  .section:first-of-type {
    margin-top:0;
  }

  .info-table, .items-table, .summary-table { width:100%; border-collapse:collapse; }

  .info-table td {
    padding:2px 0;
    vertical-align:top;
    font-size: 13px;
    font-family: Arial, sans-serif;
  }

  .items-table th {
    background:#fff;
    color:#000;
    border-bottom:1px solid #000;
    padding:4px 6px;
    font-weight:700;
    font-size:13px;
    font-family: Arial, sans-serif;
  }

  .items-table td {
    padding:5px 6px;
    border-bottom:1px solid #f0f3f5;
    vertical-align:middle;
    line-height:1.2;
    font-size:13px;
    font-family: Arial, sans-serif;
  }

  .balance-amount {
    font-size:14px;
    font-weight:600;
    white-space:nowrap;
  }

  .summary-table td {
    padding:4px 6px;
    border-bottom:1px solid #f0f3f5;
    line-height:1.1;
    font-size:13px;
    font-family: Arial, sans-serif;
  }

  .rt { text-align:right; }

  .grand-total td {
    border-top: 2px solid #000;
    border-bottom: 2px solid #000;
    font-weight:700;
  }

  .signatures { width:100%; margin-top:28px; border-collapse:collapse; }
  .signatures td { width:33.33%; padding:0 14px; text-align:center; }
  .sig-line { border-top:1px solid #111; padding-top:6px; font-size:13px; }

  .footer-note {
    font-size:13px;
    color:#000;
    text-align:center;
    margin-top:8px;
    font-family: Arial, sans-serif;
  }

  .section:last-of-type { margin-bottom:4px; }
  </style>

  <div class="page-border"></div>

  <div class="heading-label">Cash Reconciliation</div>
  <div class="cash-account-label">{{ doc.cash_account or '' }}</div>

  <!-- Document Details -->
  <div class="section">
    <table class="info-table">
      <tr>
        <td style="width: 50%;">
          Reference: <strong>{{ doc.name }}</strong><br>
          Date: {{ frappe.utils.formatdate(doc.posting_date, 'dd-MMM-yyyy') }}{% if doc.posting_time %} {{ doc.posting_time }}{% endif %}<br>
          Cashier: {{ doc.cashier or '-' }}
        </td>
        <td class="rt" style="width: 50%;">
          Status: <strong>{{ doc.reconciliation_status or '-' }}</strong><br>
          Fetched On: {{ frappe.utils.format_datetime(doc.fetched_on) if doc.fetched_on else '-' }}
        </td>
      </tr>
    </table>
  </div>

  <!-- Balances -->
  <div class="section">
    <div class="section-title">Balances</div>
    <table class="items-table">
      <thead>
        <tr>
          <th style="width:65%">Description</th>
          <th class="rt" style="width:35%">Amount ({{ doc.company_currency }})</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td>Ledger Balance</td>
          <td class="rt balance-amount">{{ frappe.utils.fmt_money(doc.ledger_balance or 0, currency=doc.company_currency) }}</td>
        </tr>
        <tr>
          <td>Physical Cash Balance</td>
          <td class="rt balance-amount">{{ frappe.utils.fmt_money(doc.physical_cash_balance or 0, currency=doc.company_currency) }}</td>
        </tr>
      </tbody>
    </table>
    <table class="summary-table">
      <tr class="grand-total">
        <td style="width:65%; border-top:2px solid #000; border-bottom:2px solid #000; padding:6px 6px; font-size:14px;"><strong>Difference</strong></td>
        <td class="rt" style="width:35%; white-space:nowrap; border-top:2px solid #000; border-bottom:2px solid #000; padding:6px 6px; font-size:15px;"><strong>{{ frappe.utils.fmt_money(doc.difference or 0, currency=doc.company_currency) }}</strong></td>
      </tr>
    </table>
  </div>

  {% if doc.period_from %}
  <!-- Period Flow Analysis -->
  <div class="section" style="margin-top:18px;">
    <div class="section-title">Period Flow Analysis</div>
    <table style="width:100%; border-collapse:collapse; margin-bottom:5px; border:1px solid #ddd;">
      <tr>
        <td style="width:33.33%; padding:3px 8px; font-size:12px; line-height:1.1; border-right:1px solid #ddd;"><strong>Period Type:</strong> {{ doc.period_type or 'Day' }}</td>
        <td style="width:33.33%; padding:3px 8px; font-size:12px; line-height:1.1; border-right:1px solid #ddd;"><strong>From:</strong> {{ frappe.utils.formatdate(doc.period_from, 'dd-MMM-yyyy') }}</td>
        <td style="width:33.33%; padding:3px 8px; font-size:12px; line-height:1.1;"><strong>To:</strong> {{ frappe.utils.formatdate(doc.period_to, 'dd-MMM-yyyy') if doc.period_to else '-' }}</td>
      </tr>
    </table>
    <table class="items-table">
      <thead>
        <tr>
          <th style="width:65%">Flow Component</th>
          <th class="rt" style="width:35%">Amount ({{ doc.company_currency }})</th>
        </tr>
      </thead>
      <tbody>
        <tr style="background:#f7f7f7;">
          <td><em>Opening Balance</em></td>
          <td class="rt balance-amount"><em>{{ frappe.utils.fmt_money(doc.period_opening_balance or 0, currency=doc.company_currency) }}</em></td>
        </tr>
        <tr>
          <td>+ Receipts (Debits)</td>
          <td class="rt balance-amount">{{ frappe.utils.fmt_money(doc.period_receipts or 0, currency=doc.company_currency) }}</td>
        </tr>
        <tr>
          <td>- Payments (Credits)</td>
          <td class="rt balance-amount">{{ frappe.utils.fmt_money(doc.period_payments or 0, currency=doc.company_currency) }}</td>
        </tr>
      </tbody>
    </table>
    <table class="summary-table">
      <tr>
        <td style="width:65%; border-top:1px solid #000; padding:5px 6px; font-size:13px;"><strong>Net Flow</strong></td>
        <td class="rt" style="width:35%; white-space:nowrap; border-top:1px solid #000; padding:5px 6px; font-size:13px;"><strong>{{ frappe.utils.fmt_money(doc.period_net_flow or 0, currency=doc.company_currency) }}</strong></td>
      </tr>
      <tr class="grand-total">
        <td style="width:65%; border-top:2px solid #000; border-bottom:2px solid #000; padding:6px 6px; font-size:14px;"><strong>Closing Balance</strong></td>
        <td class="rt" style="width:35%; white-space:nowrap; border-top:2px solid #000; border-bottom:2px solid #000; padding:6px 6px; font-size:15px;"><strong>{{ frappe.utils.fmt_money(doc.period_closing_balance or 0, currency=doc.company_currency) }}</strong></td>
      </tr>
    </table>
  </div>
  {% endif %}

  <!-- Remarks -->
  <div class="section" style="margin-top:18px;">
    <div class="section-title">Remarks</div>
    <table class="info-table">
      <tr>
        <td style="border:1px solid #333; min-height:72px; height:72px; padding:8px; vertical-align:top;">{{ doc.remarks or '' }}</td>
      </tr>
    </table>
  </div>

  <!-- Signatures -->
  <div class="section">
    <table class="signatures">
      <tr>
        <td><div class="sig-line">Prepared By</div></td>
        <td><div class="sig-line">Checked By</div></td>
        <td><div class="sig-line">Approved By</div></td>
      </tr>
    </table>
  </div>

  <div class="footer-note">
    Printed on: {{ frappe.utils.format_datetime(frappe.utils.now_datetime(), 'dd-MMM-yyyy HH:mm:ss') }}
  </div>
</div>
